def replace_emojis(file_path):
    with open(file_path, 'r', encoding='utf-8') as f:
        content = f.read()

    # Sometimes there is a space right after the emoji, we might want to keep the spacing or SVG already has margin-right.
    # Our inline style has margin-right:6px which gives nice spacing.
    for emoji, icon in icon_map.items():
        # Using simple replace. Emojis with trailing space vs no trailing space.
        # Since SVG has margin-right, we can optionally strip trailing space.
        content = content.replace(emoji + " ", icon)
        content = content.replace(emoji, icon)

    with open(file_path, 'w', encoding='utf-8') as f:
        f.write(content)

replace_emojis('static/index.html')
replace_emojis('static/app.js')
print("Emojis replaced successfully.")
